48	public:
49		void build(const TriangleBvh& bvh, const std::vector<Triangle>& triangles, uint32_t max_depth) {
50			m_nodes.clear();
51			m_dual_nodes.clear();
52	
53			// Root
54			m_nodes.emplace_back();
55			m_dual_nodes.emplace_back();
56	
57			// Start counting at the 1 root node that we already have
58			std::atomic<int> node_counter{1};
59			int n_nodes = 0;
60	
61			ThreadPool pool;
62	
63			// Only generate nodes up to max_depth-1! The dual nodes will truly reach to the max depth
64			for (uint8_t depth = 0; depth < max_depth - 1; ++depth) {
65				int n_pending_nodes_to_build = node_counter - n_nodes;
66	
67				// Reserve enough memory as if the next layer was dense. This allows parallelizing the following code
68				if (depth < max_depth - 2) {
69					m_nodes.resize(node_counter + n_pending_nodes_to_build * 8);
70				} else {
71					// Tighten the memory back down when we're done.
72					m_nodes.resize(node_counter);
73				}
74	
75				int last_n_nodes = n_nodes;
76				n_nodes = node_counter;
77				pool.parallel_for<int>(last_n_nodes, node_counter, [&](size_t parent_idx) {
78					u16vec3 child_pos_base = m_nodes[parent_idx].pos * (uint16_t)2;
79					float size = std::scalbnf(1.0f, -depth - 1);
80	
81					for (uint32_t i = 0; i < 8; ++i) {
82						u16vec3 child_pos = child_pos_base;
83						if (i & 1) {
84							++child_pos.x;
85						}
86						if (i & 2) {
87							++child_pos.y;
88						}
89						if (i & 4) {
90							++child_pos.z;
91						}
92	
93						BoundingBox bb = {size * vec3(child_pos), size * vec3(child_pos + u16vec3(1))};
94	
95						if (!bvh.touches_triangle(bb, triangles.data())) {
96							m_nodes[parent_idx].children[i] = -1;
97							continue;
98						}
99	
100						int node_idx = node_counter++;
101						m_nodes[parent_idx].children[i] = node_idx;
102	
103						// Create regular nodes one layer less deep as the dual nodes
104						if (depth < max_depth - 2) {
105							m_nodes[node_idx].pos = {(uint16_t)child_pos.x, (uint16_t)child_pos.y, (uint16_t)child_pos.z};
106							m_nodes[node_idx].depth = (uint8_t)(depth + 1);
107						}
108					}
109				});
110			}
111	
112			m_dual_nodes.resize(node_counter);
113	
114			tlog::success() << "Built TriangleOctree: depth=" << max_depth << " nodes=" << m_nodes.size()
115							<< " dual_nodes=" << m_dual_nodes.size() << ". Populating dual nodes...";
116	
117			// TODO: find a fast lockfree hashmap implementation and parallelize the bottom for loop
118			std::unordered_map<u16vec4, uint32_t> coords;
119			coords.reserve(m_dual_nodes.size() * 8);
120			m_n_vertices = 0;
121			auto generate_dual_coords = [&](TriangleOctreeDualNode& dual_node, int depth, const u16vec3 pos) {
122				for (uint32_t i = 0; i < 8; ++i) {
123					u16vec4 coord = {(uint16_t)pos.x, (uint16_t)pos.y, (uint16_t)pos.z, (uint16_t)depth};
124					if (i & 1) {
125						++coord.x;
126					}
127					if (i & 2) {
128						++coord.y;
129					}
130					if (i & 4) {
131						++coord.z;
132					}
133	
134					auto p = coords.insert({coord, m_n_vertices});
135					if (p.second) {
136						++m_n_vertices;
137					}
138	
139					dual_node.vertices[i] = p.first->second;
140				}
141			};
142	
143			generate_dual_coords(m_dual_nodes[0], 0, {(uint16_t)0, (uint16_t)0, (uint16_t)0});
144			for (auto& node : m_nodes) {
145				for (uint32_t i = 0; i < 8; ++i) {
146					auto child_idx = node.children[i];
147					if (child_idx == -1) {
148						continue;
149					}
150	
151					u16vec3 child_pos = node.pos * (uint16_t)2;
152					if (i & 1) {
153						++child_pos.x;
154					}
155					if (i & 2) {
156						++child_pos.y;
157					}
158					if (i & 4) {
159						++child_pos.z;
160					}
161	
162					generate_dual_coords(m_dual_nodes[child_idx], node.depth + 1, child_pos);
163				}
164			}
165	
166			m_depth = max_depth;
167	
168			m_nodes_gpu.resize_and_copy_from_host(m_nodes);
169			m_dual_nodes_gpu.resize_and_copy_from_host(m_dual_nodes);
170		}
