90			Program(const char* data, size_t size, OptixDeviceContext optix, bool spheres = false) {
91				char log[2048]; // For error reporting from OptiX creation functions
92				size_t sizeof_log = sizeof(log);
93	
94				// Module from PTX
95				OptixModule optix_module = nullptr;
96				OptixModuleCompileOptions module_compile_options = {};
97				OptixPipelineCompileOptions pipeline_compile_options = {};
98	
99				// Pipeline options must be consistent for all modules used in a
100				// single pipeline
101				pipeline_compile_options.usesMotionBlur = false;
102	
103				// This option is important to ensure we compile code which is optimal
104				// for our scene hierarchy. We use a single GAS � no instancing or
105				// multi-level hierarchies
106				pipeline_compile_options.traversableGraphFlags =
107					OPTIX_TRAVERSABLE_GRAPH_FLAG_ALLOW_SINGLE_GAS;
108				pipeline_compile_options.usesPrimitiveTypeFlags = spheres ? OPTIX_PRIMITIVE_TYPE_FLAGS_SPHERE : OPTIX_PRIMITIVE_TYPE_FLAGS_TRIANGLE;
109	
110				// Our device code uses 3 payload registers (r,g,b output value)
111				pipeline_compile_options.numPayloadValues = 3;
112	
113				// This is the name of the param struct variable in our device code
114				pipeline_compile_options.pipelineLaunchParamsVariableName = "params_data";
115	
116				OPTIX_CHECK_THROW_LOG(optixModuleCreateFromPTX(
117					optix,
118					&module_compile_options,
119					&pipeline_compile_options,
120					data,
121					size,
122					log,
123					&sizeof_log,
124					&optix_module
125				));
126	
127				// Program groups
128				OptixProgramGroup raygen_prog_group   = nullptr;
129				OptixProgramGroup miss_prog_group     = nullptr;
130				OptixProgramGroup hitgroup_prog_group = nullptr;
131				{
132					OptixProgramGroupOptions program_group_options   = {}; // Initialize to zeros
133	
134					OptixProgramGroupDesc raygen_prog_group_desc    = {}; //
135					raygen_prog_group_desc.kind                     = OPTIX_PROGRAM_GROUP_KIND_RAYGEN;
136					raygen_prog_group_desc.raygen.module            = optix_module;
137					raygen_prog_group_desc.raygen.entryFunctionName = "__raygen__rg";
138					OPTIX_CHECK_THROW_LOG(optixProgramGroupCreate(
139						optix,
140						&raygen_prog_group_desc,
141						1,   // num program groups
142						&program_group_options,
143						log,
144						&sizeof_log,
145						&raygen_prog_group
146					));
147	
148					OptixProgramGroupDesc miss_prog_group_desc  = {};
149					miss_prog_group_desc.kind                   = OPTIX_PROGRAM_GROUP_KIND_MISS;
150					miss_prog_group_desc.miss.module            = optix_module;
151					miss_prog_group_desc.miss.entryFunctionName = "__miss__ms";
152					OPTIX_CHECK_THROW_LOG(optixProgramGroupCreate(
153						optix,
154						&miss_prog_group_desc,
155						1,   // num program groups
156						&program_group_options,
157						log,
158						&sizeof_log,
159						&miss_prog_group
160					));
161	
162					OptixProgramGroupDesc hitgroup_prog_group_desc = {};
163					hitgroup_prog_group_desc.kind                         = OPTIX_PROGRAM_GROUP_KIND_HITGROUP;
164					hitgroup_prog_group_desc.hitgroup.moduleCH            = optix_module;
165					hitgroup_prog_group_desc.hitgroup.entryFunctionNameCH = "__closesthit__ch";
166	
167					if (spheres) {
168						OptixBuiltinISOptions is_options = {};
169						is_options.builtinISModuleType = OPTIX_PRIMITIVE_TYPE_SPHERE;
170						is_options.buildFlags = OPTIX_BUILD_FLAG_NONE;
171						is_options.usesMotionBlur = false;
172						OPTIX_CHECK_THROW(optixBuiltinISModuleGet(
173							optix,
174							&module_compile_options,
175							&pipeline_compile_options,
176							&is_options,
177							&hitgroup_prog_group_desc.hitgroup.moduleIS
178						));
179					}
180	
181					OPTIX_CHECK_THROW_LOG(optixProgramGroupCreate(
182						optix,
183						&hitgroup_prog_group_desc,
184						1,   // num program groups
185						&program_group_options,
186						log,
187						&sizeof_log,
188						&hitgroup_prog_group
189					));
190				}
191	
192				// Linking
193				{
194					const uint32_t max_trace_depth = 1;
195					OptixProgramGroup program_groups[] = { raygen_prog_group, miss_prog_group, hitgroup_prog_group };
196	
197					OptixPipelineLinkOptions pipeline_link_options = {};
198					pipeline_link_options.maxTraceDepth = max_trace_depth;
199					pipeline_link_options.debugLevel    = OPTIX_COMPILE_DEBUG_LEVEL_DEFAULT;
200	
201					OPTIX_CHECK_THROW_LOG(optixPipelineCreate(
202						optix,
203						&pipeline_compile_options,
204						&pipeline_link_options,
205						program_groups,
206						sizeof(program_groups) / sizeof(program_groups[0]),
207						log,
208						&sizeof_log,
209						&m_pipeline
210					));
211	
212					OptixStackSizes stack_sizes = {};
213					for (auto& prog_group : program_groups) {
214						OPTIX_CHECK_THROW(optixUtilAccumulateStackSizes(prog_group, &stack_sizes));
215					}
216	
217					uint32_t direct_callable_stack_size_from_traversal;
218					uint32_t direct_callable_stack_size_from_state;
219					uint32_t continuation_stack_size;
220					OPTIX_CHECK_THROW(optixUtilComputeStackSizes(
221						&stack_sizes, max_trace_depth,
222						0,  // maxCCDepth
223						0,  // maxDCDEpth
224						&direct_callable_stack_size_from_traversal,
225						&direct_callable_stack_size_from_state, &continuation_stack_size
226					));
227					OPTIX_CHECK_THROW(optixPipelineSetStackSize(
228						m_pipeline, direct_callable_stack_size_from_traversal,
229						direct_callable_stack_size_from_state, continuation_stack_size,
230						1  // maxTraversableDepth
231					));
232				}
233	
234				// Shader binding table
235				{
236					CUdeviceptr raygen_record;
237					const size_t raygen_record_size = sizeof(SbtRecord<typename T::RayGenData>);
238					CUDA_CHECK_THROW(cudaMalloc(reinterpret_cast<void**>(&raygen_record), raygen_record_size));
239					SbtRecord<typename T::RayGenData> rg_sbt;
240					OPTIX_CHECK_THROW(optixSbtRecordPackHeader(raygen_prog_group, &rg_sbt));
241					CUDA_CHECK_THROW(cudaMemcpy(
242						reinterpret_cast<void*>(raygen_record),
243						&rg_sbt,
244						raygen_record_size,
245						cudaMemcpyHostToDevice
246					));
247	
248					CUdeviceptr miss_record;
249					size_t miss_record_size = sizeof(SbtRecord<typename T::MissData>);
250					CUDA_CHECK_THROW(cudaMalloc(reinterpret_cast<void**>(&miss_record), miss_record_size));
251					SbtRecord<typename T::MissData> ms_sbt;
252					OPTIX_CHECK_THROW(optixSbtRecordPackHeader(miss_prog_group, &ms_sbt));
253					CUDA_CHECK_THROW(cudaMemcpy(
254						reinterpret_cast<void*>(miss_record),
255						&ms_sbt,
256						miss_record_size,
257						cudaMemcpyHostToDevice
258					));
259	
260					CUdeviceptr hitgroup_record;
261					size_t hitgroup_record_size = sizeof(SbtRecord<typename T::HitGroupData>);
262					CUDA_CHECK_THROW(cudaMalloc(reinterpret_cast<void**>(&hitgroup_record), hitgroup_record_size));
263					SbtRecord<typename T::HitGroupData> hg_sbt;
264					OPTIX_CHECK_THROW(optixSbtRecordPackHeader(hitgroup_prog_group, &hg_sbt));
265					CUDA_CHECK_THROW(cudaMemcpy(
266						reinterpret_cast<void*>(hitgroup_record),
267						&hg_sbt,
268						hitgroup_record_size,
269						cudaMemcpyHostToDevice
270					));
271	
272					m_sbt.raygenRecord                = raygen_record;
273					m_sbt.missRecordBase              = miss_record;
274					m_sbt.missRecordStrideInBytes     = sizeof(SbtRecord<typename T::MissData>);
275					m_sbt.missRecordCount             = 1;
276					m_sbt.hitgroupRecordBase          = hitgroup_record;
277					m_sbt.hitgroupRecordStrideInBytes = sizeof(SbtRecord<typename T::HitGroupData>);
278					m_sbt.hitgroupRecordCount         = 1;
279				}
280			}
