373	// Sorting networks from http://users.telenet.be/bertdobbelaere/SorterHunter/sorting_networks.html#N4L5D3
374	template <uint32_t N, typename T>
375	__host__ __device__ void sorting_network(T values[N]) {
376		static_assert(N <= 8, "Sorting networks are only implemented up to N==8");
377		if (N <= 1) {
378			return;
379		} else if (N == 2) {
380			compare_and_swap(values[0], values[1]);
381		} else if (N == 3) {
382			compare_and_swap(values[0], values[2]);
383			compare_and_swap(values[0], values[1]);
384			compare_and_swap(values[1], values[2]);
385		} else if (N == 4) {
386			compare_and_swap(values[0], values[2]);
387			compare_and_swap(values[1], values[3]);
388			compare_and_swap(values[0], values[1]);
389			compare_and_swap(values[2], values[3]);
390			compare_and_swap(values[1], values[2]);
391		} else if (N == 5) {
392			compare_and_swap(values[0], values[3]);
393			compare_and_swap(values[1], values[4]);
394	
395			compare_and_swap(values[0], values[2]);
396			compare_and_swap(values[1], values[3]);
397	
398			compare_and_swap(values[0], values[1]);
399			compare_and_swap(values[2], values[4]);
400	
401			compare_and_swap(values[1], values[2]);
402			compare_and_swap(values[3], values[4]);
403	
404			compare_and_swap(values[2], values[3]);
405		} else if (N == 6) {
406			compare_and_swap(values[0], values[5]);
407			compare_and_swap(values[1], values[3]);
408			compare_and_swap(values[2], values[4]);
409	
410			compare_and_swap(values[1], values[2]);
411			compare_and_swap(values[3], values[4]);
412	
413			compare_and_swap(values[0], values[3]);
414			compare_and_swap(values[2], values[5]);
415	
416			compare_and_swap(values[0], values[1]);
417			compare_and_swap(values[2], values[3]);
418			compare_and_swap(values[4], values[5]);
419	
420			compare_and_swap(values[1], values[2]);
421			compare_and_swap(values[3], values[4]);
422		} else if (N == 7) {
423			compare_and_swap(values[0], values[6]);
424			compare_and_swap(values[2], values[3]);
425			compare_and_swap(values[4], values[5]);
426	
427			compare_and_swap(values[0], values[2]);
428			compare_and_swap(values[1], values[4]);
429			compare_and_swap(values[3], values[6]);
430	
431			compare_and_swap(values[0], values[1]);
432			compare_and_swap(values[2], values[5]);
433			compare_and_swap(values[3], values[4]);
434	
435			compare_and_swap(values[1], values[2]);
436			compare_and_swap(values[4], values[6]);
437	
438			compare_and_swap(values[2], values[3]);
439			compare_and_swap(values[4], values[5]);
440	
441			compare_and_swap(values[1], values[2]);
442			compare_and_swap(values[3], values[4]);
443			compare_and_swap(values[5], values[6]);
444		} else if (N == 8) {
445			compare_and_swap(values[0], values[2]);
446			compare_and_swap(values[1], values[3]);
447			compare_and_swap(values[4], values[6]);
448			compare_and_swap(values[5], values[7]);
449	
450			compare_and_swap(values[0], values[4]);
451			compare_and_swap(values[1], values[5]);
452			compare_and_swap(values[2], values[6]);
453			compare_and_swap(values[3], values[7]);
454	
455			compare_and_swap(values[0], values[1]);
456			compare_and_swap(values[2], values[3]);
457			compare_and_swap(values[4], values[5]);
458			compare_and_swap(values[6], values[7]);
459	
460			compare_and_swap(values[2], values[4]);
461			compare_and_swap(values[3], values[5]);
462	
463			compare_and_swap(values[1], values[4]);
464			compare_and_swap(values[3], values[6]);
465	
466			compare_and_swap(values[1], values[2]);
467			compare_and_swap(values[3], values[4]);
468			compare_and_swap(values[5], values[6]);
469		}
