472	template <uint32_t BRANCHING_FACTOR>
473	class TriangleBvhWithBranchingFactor : public TriangleBvh {
474	public:
475		__host__ __device__ static std::pair<int, float> ray_intersect(const vec3& ro, const vec3& rd, const TriangleBvhNode* __restrict__ bvhnodes, const Triangle* __restrict__ triangles) {
476			FixedIntStack query_stack;
477			query_stack.push(0);
478	
479			float mint = MAX_DIST;
480			int shortest_idx = -1;
481	
482			while (!query_stack.empty()) {
483				int idx = query_stack.pop();
484	
485				const TriangleBvhNode& node = bvhnodes[idx];
486	
487				if (node.left_idx < 0) {
488					int end = -node.right_idx-1;
489					for (int i = -node.left_idx-1; i < end; ++i) {
490						float t = triangles[i].ray_intersect(ro, rd);
491						if (t < mint) {
492							mint = t;
493							shortest_idx = i;
494						}
495					}
496				} else {
497					DistAndIdx children[BRANCHING_FACTOR];
498	
499					uint32_t first_child = node.left_idx;
500	
501					NGP_PRAGMA_UNROLL
502					for (uint32_t i = 0; i < BRANCHING_FACTOR; ++i) {
503						children[i] = {bvhnodes[i+first_child].bb.ray_intersect(ro, rd).x, i+first_child};
504					}
505	
506					sorting_network<BRANCHING_FACTOR>(children);
507	
508					NGP_PRAGMA_UNROLL
509					for (uint32_t i = 0; i < BRANCHING_FACTOR; ++i) {
510						if (children[i].dist < mint) {
511							query_stack.push(children[i].idx);
512						}
513					}
514				}
515			}
516	
517			return {shortest_idx, mint};
518		}
