520		__host__ __device__ static std::pair<int, float> closest_triangle(const vec3& point, const TriangleBvhNode* __restrict__ bvhnodes, const Triangle* __restrict__ triangles, float max_distance_sq) {
521			FixedIntStack query_stack;
522			query_stack.push(0);
523	
524			float shortest_distance_sq = max_distance_sq;
525			int shortest_idx = -1;
526	
527			while (!query_stack.empty()) {
528				int idx = query_stack.pop();
529	
530				const TriangleBvhNode& node = bvhnodes[idx];
531	
532				if (node.left_idx < 0) {
533					int end = -node.right_idx-1;
534					for (int i = -node.left_idx-1; i < end; ++i) {
535						float dist_sq = triangles[i].distance_sq(point);
536						if (dist_sq <= shortest_distance_sq) {
537							shortest_distance_sq = dist_sq;
538							shortest_idx = i;
539						}
540					}
541				} else {
542					DistAndIdx children[BRANCHING_FACTOR];
543	
544					uint32_t first_child = node.left_idx;
545	
546					NGP_PRAGMA_UNROLL
547					for (uint32_t i = 0; i < BRANCHING_FACTOR; ++i) {
548						children[i] = {bvhnodes[i+first_child].bb.distance_sq(point), i+first_child};
549					}
550	
551					sorting_network<BRANCHING_FACTOR>(children);
552	
553					NGP_PRAGMA_UNROLL
554					for (uint32_t i = 0; i < BRANCHING_FACTOR; ++i) {
555						if (children[i].dist <= shortest_distance_sq) {
556							query_stack.push(children[i].idx);
557						}
558					}
559				}
560			}
561	
562			if (shortest_idx == -1) {
563				// printf("No closest triangle found. This must be a bug! %d\n", BRANCHING_FACTOR);
564				shortest_idx = 0;
565				shortest_distance_sq = 0.0f;
566			}
567	
568			return {shortest_idx, std::sqrt(shortest_distance_sq)};
569		}
