571		// Assumes that "point" is a location on a triangle
572		__host__ __device__ static vec3 avg_normal_around_point(const vec3& point, const TriangleBvhNode* __restrict__ bvhnodes, const Triangle* __restrict__ triangles) {
573			FixedIntStack query_stack;
574			query_stack.push(0);
575	
576			static constexpr float EPSILON = 1e-12f;
577	
578			uint32_t n_tris = 0;
579			vec3 normal_weighted_sum = vec3(0.0f);
580			vec3 normal_sum = vec3(0.0f);
581	
582			while (!query_stack.empty()) {
583				int idx = query_stack.pop();
584	
585				const TriangleBvhNode& node = bvhnodes[idx];
586	
587				if (node.left_idx < 0) {
588					int end = -node.right_idx-1;
589					for (int i = -node.left_idx-1; i < end; ++i) {
590						const Triangle& tri = triangles[i];
591						if (tri.distance_sq(point) < EPSILON) {
592							vec3 n = tri.normal();
593							normal_sum += n;
594							normal_weighted_sum += tri.angle_at_pos(point) * n;
595							++n_tris;
596						}
597					}
598				} else {
599					uint32_t first_child = node.left_idx;
600	
601					NGP_PRAGMA_UNROLL
602					for (uint32_t i = 0; i < BRANCHING_FACTOR; ++i) {
603						if (bvhnodes[i+first_child].bb.distance_sq(point) < EPSILON) {
604							query_stack.push(i+first_child);
605						}
606					}
607				}
608			}
609	
610			if (n_tris < 3) {
611				return normalize(normal_sum);
612			} else {
613				return normalize(normal_weighted_sum);
614			}
615		}
616	
617		__host__ __device__ static float unsigned_distance(const vec3& point, const TriangleBvhNode* __restrict__ bvhnodes, const Triangle* __restrict__ triangles, float max_distance_sq) {
618			return closest_triangle(point, bvhnodes, triangles, max_distance_sq).second;
619		}
620	
621		__host__ __device__ static float signed_distance_watertight(const vec3& point, const TriangleBvhNode* __restrict__ bvhnodes, const Triangle* __restrict__ triangles, float max_distance_sq) {
622			auto p = closest_triangle(point, bvhnodes, triangles, max_distance_sq);
623	
624			const Triangle& tri = triangles[p.first];
625			vec3 closest_point = tri.closest_point(point);
626			vec3 avg_normal = avg_normal_around_point(closest_point, bvhnodes, triangles);
627	
628			return copysign(avg_normal == vec3(0.0f) ? 0.0f : p.second, dot(avg_normal, point - closest_point));
629		}
630	
631		__host__ __device__ static float signed_distance_raystab(const vec3& point, const TriangleBvhNode* __restrict__ bvhnodes, const Triangle* __restrict__ triangles, float max_distance_sq, default_rng_t rng={}) {
632			float distance = unsigned_distance(point, bvhnodes, triangles, max_distance_sq);
633	
634			vec2 offset = random_val_2d(rng);
635	
636			static constexpr uint32_t N_STAB_RAYS = 32;
637			for (uint32_t i = 0; i < N_STAB_RAYS; ++i) {
638				// Use a Fibonacci lattice (with random offset) to regularly
639				// distribute the stab rays over the sphere.
640				vec3 d = fibonacci_dir<N_STAB_RAYS>(i, offset);
641	
642				// If any of the stab rays goes outside the mesh, the SDF is positive.
643				if (ray_intersect(point, d, bvhnodes, triangles).first < 0) {
644					return distance;
645				}
646			}
647	
648			return -distance;
649		}
650	
651		// Assumes that "point" is a location on a triangle
652		vec3 avg_normal_around_point(const vec3& point, const Triangle* __restrict__ triangles) const {
653			return avg_normal_around_point(point, m_nodes.data(), triangles);
654		}
655	
656		float signed_distance(EMeshSdfMode mode, const vec3& point, const std::vector<Triangle>& triangles) const {
657			if (mode == EMeshSdfMode::Watertight) {
658				return signed_distance_watertight(point, m_nodes.data(), triangles.data(), MAX_DIST*MAX_DIST);
659			} else {
660				return signed_distance_raystab(point, m_nodes.data(), triangles.data(), MAX_DIST*MAX_DIST);
661			}
662		}
663	
664		void signed_distance_gpu(uint32_t n_elements, EMeshSdfMode mode, const vec3* gpu_positions, float* gpu_distances, const Triangle* gpu_triangles, bool use_existing_distances_as_upper_bounds, cudaStream_t stream) override {
665			if (mode == EMeshSdfMode::Watertight) {
666				linear_kernel(signed_distance_watertight_kernel, 0, stream,
667					n_elements,
668					gpu_positions,
669					m_nodes_gpu.data(),
670					gpu_triangles,
671					gpu_distances,
672					use_existing_distances_as_upper_bounds
673				);
674			} else {
675	#ifdef NGP_OPTIX
676				if (m_optix.available) {
677					linear_kernel(unsigned_distance_kernel, 0, stream,
678						n_elements,
679						gpu_positions,
680						m_nodes_gpu.data(),
681						gpu_triangles,
682						gpu_distances,
683						use_existing_distances_as_upper_bounds
684					);
685	
686					if (mode == EMeshSdfMode::Raystab) {
687						m_optix.raystab->invoke({gpu_positions, gpu_distances, m_optix.gas->handle()}, {n_elements, 1, 1}, stream);
688					} else if (mode == EMeshSdfMode::PathEscape) {
689						m_optix.pathescape->invoke({gpu_positions, gpu_triangles, gpu_distances, m_optix.gas->handle()}, {n_elements, 1, 1}, stream);
690					}
691				} else
692	#endif //NGP_OPTIX
693				{
694					if (mode == EMeshSdfMode::Raystab) {
695						linear_kernel(signed_distance_raystab_kernel, 0, stream,
696							n_elements,
697							gpu_positions,
698							m_nodes_gpu.data(),
699							gpu_triangles,
700							gpu_distances,
701							use_existing_distances_as_upper_bounds
702						);
703					} else if (mode == EMeshSdfMode::PathEscape) {
704						throw std::runtime_error{"TriangleBvh: EMeshSdfMode::PathEscape is only supported with OptiX enabled."};
705					}
706				}
707			}
708		}
709	
710		void ray_trace_gpu(uint32_t n_elements, vec3* gpu_positions, vec3* gpu_directions, const Triangle* gpu_triangles, cudaStream_t stream) override {
711	#ifdef NGP_OPTIX
712			if (m_optix.available) {
713				m_optix.raytrace->invoke({gpu_positions, gpu_directions, gpu_triangles, m_optix.gas->handle()}, {n_elements, 1, 1}, stream);
714			} else
715	#endif //NGP_OPTIX
716			{
717				linear_kernel(raytrace_kernel, 0, stream,
718					n_elements,
719					gpu_positions,
720					gpu_directions,
721					m_nodes_gpu.data(),
722					gpu_triangles
723				);
724			}
725		}
726	
727		bool touches_triangle(const BoundingBox& bb, const TriangleBvhNode& node, const Triangle* __restrict__ triangles) const {
728			if (!node.bb.intersects(bb)) {
729				return false;
730			}
731	
732			if (node.left_idx < 0) {
733				// Touches triangle leaves?
734				int end = -node.right_idx-1;
735				for (int i = -node.left_idx-1; i < end; ++i) {
736					if (bb.intersects(triangles[i])) {
737						return true;
738					}
739				}
740			} else {
741				// Touches children?
742				int child_idx = node.left_idx;
743				for (int i = 0; i < BRANCHING_FACTOR; ++i) {
744					if (touches_triangle(bb, m_nodes[i+child_idx], triangles)) {
745						return true;
746					}
747				}
748			}
749	
750			return false;
751		}
752	
753		bool touches_triangle(const BoundingBox& bb, const Triangle* __restrict__ triangles) const override {
754			return touches_triangle(bb, m_nodes.front(), triangles);
755		}
756	
757		void build(std::vector<Triangle>& triangles, uint32_t n_primitives_per_leaf) override {
758			m_nodes.clear();
759	
760			// Root
761			m_nodes.emplace_back();
762			m_nodes.front().bb = BoundingBox(triangles.data(), triangles.data() + triangles.size());
763	
764			struct BuildNode {
765				int node_idx;
766				std::vector<Triangle>::iterator begin;
767				std::vector<Triangle>::iterator end;
768			};
769	
770			std::stack<BuildNode> build_stack;
771			build_stack.push({0, std::begin(triangles), std::end(triangles)});
772	
773			while (!build_stack.empty()) {
774				const BuildNode& curr = build_stack.top();
775				size_t node_idx = curr.node_idx;
776	
777				std::array<BuildNode, BRANCHING_FACTOR> children;
778				children[0].begin = curr.begin;
779				children[0].end = curr.end;
780	
781				build_stack.pop();
782	
783				// Partition the triangles into the children
784				int n_children = 1;
785				while (n_children < BRANCHING_FACTOR) {
786					for (int i = n_children - 1; i >= 0; --i) {
787						auto& child = children[i];
788	
789						// Choose axis with maximum standard deviation
790						vec3 mean = vec3(0.0f);
791						for (auto it = child.begin; it != child.end; ++it) {
792							mean += it->centroid();
793						}
794						mean /= (float)std::distance(child.begin, child.end);
795	
796						vec3 var = vec3(0.0f);
797						for (auto it = child.begin; it != child.end; ++it) {
798							vec3 diff = it->centroid() - mean;
799							var += diff * diff;
800						}
801						var /= (float)std::distance(child.begin, child.end);
802	
803						float max_val = max(var);
804						int axis = var.x == max_val ? 0 : (var.y == max_val ? 1 : 2);
805	
806						auto m = child.begin + std::distance(child.begin, child.end)/2;
807						std::nth_element(child.begin, m, child.end, [&](const Triangle& tri1, const Triangle& tri2) { return tri1.centroid(axis) < tri2.centroid(axis); });
808	
809						children[i*2].begin = children[i].begin;
810						children[i*2+1].end = children[i].end;
811						children[i*2].end = children[i*2+1].begin = m;
812					}
813	
814					n_children *= 2;
815				}
816	
817				// Create next build nodes
818				m_nodes[node_idx].left_idx = (int)m_nodes.size();
819				for (uint32_t i = 0; i < BRANCHING_FACTOR; ++i) {
820					auto& child = children[i];
821					assert(child.begin != child.end);
822					child.node_idx = (int)m_nodes.size();
823	
824					m_nodes.emplace_back();
825					m_nodes.back().bb = BoundingBox(&*child.begin, &*child.end);
826	
827					if (std::distance(child.begin, child.end) <= n_primitives_per_leaf) {
828						m_nodes.back().left_idx = -(int)std::distance(std::begin(triangles), child.begin)-1;
829						m_nodes.back().right_idx = -(int)std::distance(std::begin(triangles), child.end)-1;
830					} else {
831						build_stack.push(child);
832					}
833				}
834				m_nodes[node_idx].right_idx = (int)m_nodes.size();
835			}
836	
837			m_nodes_gpu.resize_and_copy_from_host(m_nodes);
838	
839			tlog::success() << "Built TriangleBvh: nodes=" << m_nodes.size();
840		}
841	
842		void build_optix(const GPUMemory<Triangle>& triangles, cudaStream_t stream) override {
843	#ifdef NGP_OPTIX
844			m_optix.available = optix::initialize();
845			if (m_optix.available) {
846				m_optix.gas = std::make_unique<optix::Gas>(triangles, g_optix, stream);
847				m_optix.raystab = std::make_unique<optix::Program<Raystab>>((const char*)optix_ptx::raystab_ptx, sizeof(optix_ptx::raystab_ptx), g_optix);
848				m_optix.raytrace = std::make_unique<optix::Program<Raytrace>>((const char*)optix_ptx::raytrace_ptx, sizeof(optix_ptx::raytrace_ptx), g_optix);
849				m_optix.pathescape = std::make_unique<optix::Program<PathEscape>>((const char*)optix_ptx::pathescape_ptx, sizeof(optix_ptx::pathescape_ptx), g_optix);
850				tlog::success() << "Built OptiX GAS and shaders";
851			} else {
852				tlog::warning() << "Falling back to slower TriangleBVH::ray_intersect.";
853			}
854	#else //NGP_OPTIX
855			tlog::warning() << "OptiX was not built. Falling back to slower TriangleBVH::ray_intersect.";
856	#endif //NGP_OPTIX
857		}
858	
859		TriangleBvhWithBranchingFactor() {}
860	
861	private:
862	#ifdef NGP_OPTIX
863		struct {
864			std::unique_ptr<optix::Gas> gas;
865			std::unique_ptr<optix::Program<Raystab>> raystab;
866			std::unique_ptr<optix::Program<Raytrace>> raytrace;
867			std::unique_ptr<optix::Program<PathEscape>> pathescape;
868			bool available = false;
869		} m_optix;
870	#endif //NGP_OPTIX
871	};
872	
873	using TriangleBvh4 = TriangleBvhWithBranchingFactor<4>;
874	
875	std::unique_ptr<TriangleBvh> TriangleBvh::make() {
876		return std::unique_ptr<TriangleBvh>(new TriangleBvh4());
877	}
878	
879	__global__ void signed_distance_watertight_kernel(uint32_t n_elements,
880		const vec3* __restrict__ positions,
881		const TriangleBvhNode* __restrict__ bvhnodes,
882		const Triangle* __restrict__ triangles,
883		float* __restrict__ distances,
884		bool use_existing_distances_as_upper_bounds
885	) {
886		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
887		if (i >= n_elements) return;
888	
889		float max_distance = use_existing_distances_as_upper_bounds ? distances[i] : MAX_DIST;
890		distances[i] = TriangleBvh4::signed_distance_watertight(positions[i], bvhnodes, triangles, max_distance*max_distance);
891	}
892	
893	__global__ void signed_distance_raystab_kernel(
894		uint32_t n_elements,
895		const vec3* __restrict__ positions,
896		const TriangleBvhNode* __restrict__ bvhnodes,
897		const Triangle* __restrict__ triangles,
898		float* __restrict__ distances,
899		bool use_existing_distances_as_upper_bounds
900	) {
901		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
902		if (i >= n_elements) return;
903	
904		float max_distance = use_existing_distances_as_upper_bounds ? distances[i] : MAX_DIST;
905		default_rng_t rng;
906		rng.advance(i * 2);
907	
908		distances[i] = TriangleBvh4::signed_distance_raystab(positions[i], bvhnodes, triangles, max_distance*max_distance, rng);
909	}
910	
911	__global__ void unsigned_distance_kernel(uint32_t n_elements,
912		const vec3* __restrict__ positions,
913		const TriangleBvhNode* __restrict__ bvhnodes,
914		const Triangle* __restrict__ triangles,
915		float* __restrict__ distances,
916		bool use_existing_distances_as_upper_bounds
917	) {
918		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
919		if (i >= n_elements) return;
920	
921		float max_distance = use_existing_distances_as_upper_bounds ? distances[i] : MAX_DIST;
922		distances[i] = TriangleBvh4::unsigned_distance(positions[i], bvhnodes, triangles, max_distance*max_distance);
923	}
924	
925	__global__ void raytrace_kernel(uint32_t n_elements, vec3* __restrict__ positions, vec3* __restrict__ directions, const TriangleBvhNode* __restrict__ nodes, const Triangle* __restrict__ triangles) {
926		uint32_t i = blockIdx.x * blockDim.x + threadIdx.x;
927		if (i >= n_elements) return;
928	
929		auto pos = positions[i];
930		auto dir = directions[i];
931	
932		auto p = TriangleBvh4::ray_intersect(pos, dir, nodes, triangles);
933		positions[i] = pos + p.second * dir;
934	
935		if (p.first >= 0) {
936			directions[i] = triangles[p.first].normal();
937		}
938	}
939	
940	}
