27	struct Onb {
28		inline __device__ Onb(const vec3& normal) {
29			m_normal = normal;
30	
31			if (fabs(m_normal.x) > fabs(m_normal.z)) {
32				m_binormal.x = -m_normal.y;
33				m_binormal.y =  m_normal.x;
34				m_binormal.z =  0;
35			} else {
36				m_binormal.x =  0;
37				m_binormal.y = -m_normal.z;
38				m_binormal.z =  m_normal.y;
39			}
40	
41			m_binormal = normalize(m_binormal);
42			m_tangent = cross(m_binormal, m_normal);
43		}
44	
45		inline __device__ void inverse_transform(vec3& p) const {
46			p = p.x*m_tangent + p.y*m_binormal + p.z*m_normal;
47		}
48	
49		vec3 m_tangent;
50		vec3 m_binormal;
51		vec3 m_normal;
52	};
