60		vec3 query_point = params->ray_origins[idx.x];
61	
62		static constexpr uint32_t N_PATHS = 32;
63		static constexpr uint32_t N_BOUNCES = 4;
64	
65		default_rng_t rng;
66		rng.advance(idx.x * 4 * N_PATHS * N_BOUNCES);
67		uint32_t n_escaped = 0;
68		for (uint32_t i = 0; i < N_PATHS; ++i) {
69			vec3 ray_origin = query_point;
