	GPUMemoryArena::Allocation alloc;
	auto scratch = allocate_workspace_and_distribute<vec3>(m_stream.get(), &alloc, n_elements);
	vec3* positions = std::get<0>(scratch);
	float* sdf_out = density.data();
	const dim3 threads = {16, 8, 1};
